//! Minimal Rust code writer for syntaqlite codegen
//!
//! Mirrors `CWriter`'s core pattern: single String buffer with indentation tracking.
//! Use `lines()` for multiline static blocks; use `line()` + `indent()`/`dedent()`
//! for dynamic content in loops.

use std::fmt::Write as _;

const RUST_FILE_HEADER: &str = "\
// Copyright 2025 The syntaqlite Authors. All rights reserved.
// Licensed under the Apache License, Version 2.0.
//
// @generated by syntaqlite-codegen — DO NOT EDIT

";

/// Simple Rust code writer with single-buffer output and indentation tracking
pub struct RustWriter {
    buffer: String,
    indent: usize,
    at_line_start: bool,
}

impl RustWriter {
    // ========== Public API ==========

    pub fn new() -> Self {
        Self {
            buffer: String::new(),
            indent: 0,
            at_line_start: true,
        }
    }

    pub fn finish(self) -> String {
        self.buffer
    }

    // Basic output

    pub fn newline(&mut self) -> &mut Self {
        self.buffer.push('\n');
        self.at_line_start = true;
        self
    }

    pub fn line(&mut self, text: &str) -> &mut Self {
        self.write_indent();
        self.buffer.push_str(text);
        self.newline()
    }

    /// Emit a block opener and increase indentation.
    ///
    /// Example: `open_block("impl Foo {")`.
    pub fn open_block(&mut self, header: &str) -> &mut Self {
        self.line(header);
        self.indent()
    }

    /// Decrease indentation and emit a block closer.
    ///
    /// Example: `close_block("}")`.
    pub fn close_block(&mut self, footer: &str) -> &mut Self {
        self.dedent();
        self.line(footer)
    }

    /// Emit a multiline string block, stripping common leading whitespace.
    ///
    /// Leading/trailing blank lines are trimmed. The minimum indentation across
    /// non-empty lines is stripped, then each line is emitted at the writer's
    /// current indent level. Empty lines become blank lines (no trailing spaces).
    ///
    /// ```ignore
    /// w.lines("
    ///     pub fn foo() {
    ///         body
    ///     }
    /// ");
    /// ```
    pub fn lines(&mut self, text: &str) -> &mut Self {
        let raw_lines: Vec<&str> = text.lines().collect();

        // Trim leading/trailing empty lines
        let start = raw_lines
            .iter()
            .position(|l| !l.trim().is_empty())
            .unwrap_or(0);
        let end = raw_lines
            .iter()
            .rposition(|l| !l.trim().is_empty())
            .map(|i| i + 1)
            .unwrap_or(0);
        if start >= end {
            return self;
        }
        let lines = &raw_lines[start..end];

        // Find minimum indentation among non-empty lines
        let min_indent = lines
            .iter()
            .filter(|l| !l.trim().is_empty())
            .map(|l| l.len() - l.trim_start().len())
            .min()
            .unwrap_or(0);

        for line in lines {
            if line.trim().is_empty() {
                self.newline();
            } else {
                let stripped = &line[min_indent..];
                self.line(stripped);
            }
        }
        self
    }

    /// Write a fragment (anything that implements Display)
    pub fn fragment(&mut self, fragment: &impl std::fmt::Display) -> &mut Self {
        write!(self.buffer, "{}", fragment).unwrap();
        self.newline()
    }

    /// Start a block (increase indentation)
    pub fn indent(&mut self) -> &mut Self {
        self.indent += 1;
        self
    }

    /// End a block (decrease indentation)
    pub fn dedent(&mut self) -> &mut Self {
        self.indent = self.indent.saturating_sub(1);
        self
    }

    /// Emit the syntaqlite copyright + @generated header.
    pub fn file_header(&mut self) {
        self.buffer.push_str(RUST_FILE_HEADER);
        self.at_line_start = true;
    }

    /// Emit a doc comment line: `/// text` (or just `///` if text is empty)
    pub fn doc_comment(&mut self, text: &str) -> &mut Self {
        self.write_indent();
        if text.is_empty() {
            self.buffer.push_str("///");
        } else {
            write!(self.buffer, "/// {}", text).unwrap();
        }
        self.newline()
    }

    // ========== Private helpers ==========

    fn write_indent(&mut self) {
        if self.at_line_start && self.indent > 0 {
            for _ in 0..self.indent {
                self.buffer.push_str("    ");
            }
        }
        self.at_line_start = false;
    }
}

impl Default for RustWriter {
    fn default() -> Self {
        Self::new()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_lines_strips_common_indent() {
        let mut w = RustWriter::new();
        w.lines(
            "
            pub fn foo() {
                body
            }
        ",
        );
        let output = w.finish();
        assert_eq!(output, "pub fn foo() {\n    body\n}\n");
    }

    #[test]
    fn test_lines_respects_writer_indent() {
        let mut w = RustWriter::new();
        w.indent();
        w.lines(
            "
            fn bar() {
                x
            }
        ",
        );
        let output = w.finish();
        assert_eq!(output, "    fn bar() {\n        x\n    }\n");
    }

    #[test]
    fn test_lines_with_empty_lines() {
        let mut w = RustWriter::new();
        w.lines(
            "
            a

            b
        ",
        );
        let output = w.finish();
        assert_eq!(output, "a\n\nb\n");
    }
}
